def _format_duration(seconds):
    if seconds < 0:
        seconds = 0
    total_seconds = int(round(seconds))
    hours = total_seconds // 3600
    minutes = (total_seconds % 3600) // 60
    secs = total_seconds % 60
    return f"{hours:02d}:{minutes:02d}:{secs:02d}"


def _to_runtime_path(path):
    if not path:
        return path

    path = str(path)
    if os.name == 'nt':
        return path

    normalized = path.replace('\\', '/')
    if len(normalized) >= 2 and normalized[1] == ':':
        drive_letter = normalized[0].lower()
        tail = normalized[2:].lstrip('/')
        return f"/mnt/{drive_letter}/{tail}" if tail else f"/mnt/{drive_letter}"

    return path


def _model_path(filename):
    return _to_runtime_path(os.path.join(model_dir, filename))


def _to_windows_path(path):
    if not path:
        return path

    normalized = str(path).replace('/', '\\')
    if len(normalized) >= 7 and normalized.lower().startswith('\\mnt\\') and normalized[5].isalpha():
        drive_letter = normalized[5]
        tail = normalized[7:]
        return f"{drive_letter.upper()}:\\{tail}" if tail else f"{drive_letter.upper()}:\\"

    return normalized


def _normalize_genre_label(label):
    text = str(label or "").strip()
    return text.split("---", 1)[1] if text.startswith("Electronic---") else text


def _save_phase1_results(results_path, results):
    os.makedirs(os.path.dirname(results_path), exist_ok=True)
    temp_path = f"{results_path}.tmp"
    with open(temp_path, 'w', encoding='utf-8') as f:
        json.dump(results, f, ensure_ascii=False, indent=2)
    os.replace(temp_path, results_path)


def _save_json_file(output_path, payload):
    os.makedirs(os.path.dirname(output_path), exist_ok=True)
    temp_path = f"{output_path}.tmp"
    with open(temp_path, 'w', encoding='utf-8') as f:
        json.dump(payload, f, ensure_ascii=False, indent=2)
    os.replace(temp_path, output_path)


